const logs = $input.all();

// Calculate date range for report title
const now = new Date();
const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
const reportMonth = monthNames[lastMonth.getMonth()];
const reportYear = lastMonth.getFullYear();

const stats = {
  reportPeriod: `${reportMonth} ${reportYear}`,
  total: logs.length,
  success: logs.filter(l => l.json.status === 'success').length,
  errors: logs.filter(l => l.json.status === 'error').length,
  timeSaved: logs.reduce((sum, l) => sum + (l.json.time_saved_minutes || 0), 0),
  byWorkflow: {},
  errorList: []
};

stats.successRate = stats.total > 0
  ? ((stats.success / stats.total) * 100).toFixed(1)
  : 0;

stats.timeSavedHours = (stats.timeSaved / 60).toFixed(1);

// Group by workflow
logs.forEach(l => {
  const wf = l.json.workflow_name || 'Unknown';
  if (!stats.byWorkflow[wf]) {
    stats.byWorkflow[wf] = { total: 0, success: 0, errors: 0, timeSaved: 0 };
  }
  stats.byWorkflow[wf].total++;
  stats.byWorkflow[wf].timeSaved += l.json.time_saved_minutes || 0;
  if (l.json.status === 'success') stats.byWorkflow[wf].success++;
  else stats.byWorkflow[wf].errors++;
});

// Collect errors (last 10)
stats.errorList = logs
  .filter(l => l.json.status === 'error')
  .slice(-10)
  .map(l => ({
    workflow: l.json.workflow_name || 'Unknown',
    message: l.json.error_message || 'No message',
    url: l.json.execution_url || '',
    date: l.json.created_at
  }));

return [{ json: stats }];

